import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import { Eye, EyeOff, Cpu, Zap } from 'lucide-react';
import AuthCard from '../components/AuthCard';

const LoginPage = () => {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [showPass, setShowPass] = useState(false);
  const [loading, setLoading] = useState(false);
  const [focused, setFocused] = useState(null);

  const { login } = useAuth();
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !password) return toast.error('Please enter your credentials.');
    setLoading(true);
    try {
      await login(email, password);
      toast.success('Welcome back to Finify!');
      navigate('/dashboard');
    } catch {
      toast.error('Invalid credentials. Please try again.');
    } finally {
      setLoading(false);
    }
  };

  const labelStyle = (field) => ({
    display: 'block', 
    fontSize: '0.6rem', 
    fontWeight: 700,
    textTransform: 'uppercase', 
    letterSpacing: '0.18em',
    color: focused === field ? 'var(--accent-primary)' : 'var(--text-muted)',
    marginBottom: '0.4rem', 
    transition: 'color 0.2s ease',
  });

  const inputStyle = {
    width: '100%',
    boxSizing: 'border-box',
    WebkitBoxShadow: '0 0 0px 1000px var(--card-bg) inset',
    WebkitTextFillColor: 'var(--text-primary)',
    caretColor: 'var(--accent-primary)',
  };

  const inputProps = {
    className: 'cyber-input',
    autoComplete: 'email',
    required: true,
    style: inputStyle,
  };

  return (
    <AuthCard
      title="Welcome Back"
      subtitle="Sign in to access your node"
      icon={Cpu}
      footerText={
        <>
          No account?{' '}
          <Link
            to="/register"
            style={{ color: 'var(--accent-primary)', textDecoration: 'none', fontWeight: 700 }}
          >
            Create one
          </Link>
        </>
      }
    >
      <form onSubmit={handleSubmit} noValidate style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
        <div>
          <label htmlFor="login-email" style={labelStyle('email')}>
            Email Address
          </label>
          <input
            id="login-email"
            type="email"
            placeholder="operator@finify.ai"
            value={email}
            onChange={e => setEmail(e.target.value)}
            onFocus={() => setFocused('email')}
            onBlur={() => setFocused(null)}
            {...inputProps}
          />
        </div>

        <div>
          <label htmlFor="login-password" style={labelStyle('password')}>
            Master Key
          </label>
          <div style={{ position: 'relative' }}>
            <input
              id="login-password"
              type={showPass ? 'text' : 'password'}
              placeholder="••••••••"
              value={password}
              onChange={e => setPassword(e.target.value)}
              onFocus={() => setFocused('password')}
              onBlur={() => setFocused(null)}
              autoComplete="current-password"
              {...inputProps}
              style={{ ...inputProps, paddingRight: '3rem' }}
            />
            <button
              type="button"
              onClick={() => setShowPass(v => !v)}
              aria-label={showPass ? 'Hide password' : 'Show password'}
              style={{
                position: 'absolute',
                right: '0.875rem',
                top: '50%',
                transform: 'translateY(-50%)',
                background: 'none',
                border: 'none',
                padding: 0,
                cursor: 'pointer',
                color: 'var(--text-muted)',
                display: 'flex',
                alignItems: 'center',
                transition: 'color 0.2s ease',
              }}
              onMouseEnter={e => e.currentTarget.style.color = 'var(--accent-primary)'}
              onMouseLeave={e => e.currentTarget.style.color = 'var(--text-muted)'}
            >
              {showPass ? <EyeOff size={15} /> : <Eye size={15} />}
            </button>
          </div>
        </div>

        <div style={{ textAlign: 'right', marginTop: '-0.25rem' }}>
          <Link
            to="/forgot-password"
            style={{
              fontSize: '0.6rem',
              textTransform: 'uppercase',
              letterSpacing: '0.15em',
              color: 'var(--text-muted)',
              textDecoration: 'none',
            }}
          >
            Forgot key?
          </Link>
        </div>

        <button
          type="submit"
          className="cyber-btn"
          disabled={loading}
          style={{ marginTop: '0.25rem' }}
        >
          {loading ? (
            <>
              <Zap size={13} style={{ animation: 'pulse 1s ease-in-out infinite' }} /> SYNCHRONIZING...
            </>
          ) : (
            'Access Node'
          )}
        </button>
      </form>
    </AuthCard>
  );
};

export default LoginPage;
